const input = $input.first().json;
let text = '';

if (input.body && input.body.text) {
  text = input.body.text;
} else if (input.body) {
  text = JSON.stringify(input.body);
}

if (!text || text.length < 10) {
  return [{ json: { error: 'Please provide text in the request body as { "text": "your text here" }', text: '', valid: false } }];
}

// Truncate very long texts to stay within model context
const maxLength = 8000;
const truncated = text.length > maxLength;
text = text.substring(0, maxLength);

return [{ json: { text, original_length: input.body.text ? input.body.text.length : 0, truncated, valid: true } }];

const ollamaResponse = $input.first().json;
let response;

try {
  response = typeof ollamaResponse.data === 'string' ? JSON.parse(ollamaResponse.data) : ollamaResponse;
} catch (e) {
  response = ollamaResponse;
}

const summary = response.response || response.data?.response || 'Unable to generate summary';
const inputMeta = $('Validate & Prepare Input').first().json;

return [{
  json: {
    summary: summary,
    metadata: {
      original_length: inputMeta.original_length,
      was_truncated: inputMeta.truncated,
      model: 'llama3.1:8b',
      processed_at: new Date().toISOString()
    }
  }
}];
